#include<bits/stdc++.h>
using namespace std;
const int N=1e6+5;
int mp[N];//最大质因子
int n,b,ans=0;
void work(int n){
	mp[1]=1;
	for(int i=2;i<=n;i++){
		if(!mp[i]){//如果是质数
			mp[i]=i;//其最大质因子为其本身
			for(int j=2;i*j<=n;j++){//将所有i的倍数枚举
				mp[i*j]=i;
			}
		}
	}
}
int main(){
	cin>>n>>b;
	work(n);
	for(int i=1;i<=n;i++){
		if(mp[i]<=b)ans++;
	}
	cout<<ans;
	return 0;
}
